contract TokenSale {
    struct Token {
        uint256 supply;
        uint256 price;
        uint256 quantity;
        uint256 lockIn;
        uint256 totalSupply;
    }

    mapping(address => Token) public tokens;

    uint256 public initialSupply;
    uint256 public maxSupply;

    uint256 public totalSupply;
    uint256 public lockedSupply;

    function createToken(uint256 _supply, uint256 _price, uint256 _quantity, uint256 _lockIn, uint256 _totalSupply) public {
        tokens[msg.sender] = Token(_supply, _price, _quantity, _lockIn, _totalSupply);
        lockedSupply += _lockIn;
        totalSupply += _totalSupply;
    }

    function transferTokens(address _from, address _to, uint256 _amount) public {
        require(msg.sender == _from || lockedSupply >= _amount, "Transfer tokens is not possible.");
        require(msg.sender == _to || lockedSupply < 0, "Transfer tokens is not possible.");
        tokens[_from].quantity -= _amount;
        tokens[_to].quantity += _amount;
        lockedSupply -= _amount;
        totalSupply -= _amount;
    }

    function lockTokens(address _from, address _to) public {
        require(msg.sender == _from || lockedSupply >= _to, "Lock tokens is not possible.");
        lockedSupply += _to;
        totalSupply += _to;
    }

    function unlockTokens(address _from, address _to) public {
        require(msg.sender == _from || lockedSupply >= _to, "Unlock tokens is not possible.");
        lockedSupply -= _to;
        totalSupply -= _to;
    }

